+/**
+ * Notification log model — tracks sent notification history.
+ *
+ * Each log entry captures the full context of a notification delivery attempt:
+ * recipient, channel, type, delivery status, and timing.
+ */
+
+import type { NotificationChannel, NotificationPriority, NotificationType } from './notification.js';
+
+/**
+ * Delivery status of a logged notification.
+ */
+export type DeliveryStatus = 'sent' | 'failed' | 'pending';
+
+/**
+ * A notification history log entry.
+ */
+export interface NotificationLog {
+  id: string;
+  notificationId: string;
+  recipient: string;
+  channel: NotificationChannel;
+  notificationType: NotificationType;
+  priority: NotificationPriority;
+  subject: string;
+  status: DeliveryStatus;
+  error?: string;
+  metadata?: Record<string, string>;
+  createdAt: Date;
+  deliveredAt?: Date;
+}
+
+/**
+ * Filter criteria for querying notification history.
+ */
+export interface NotificationLogQuery {
+  recipient?: string;
+  notificationType?: NotificationType;
+  channel?: NotificationChannel;
+  status?: DeliveryStatus;
+  startDate?: Date;
+  endDate?: Date;
+}

