+/**
+ * Notification history service — logs all sent notifications for auditing and querying.
+ *
+ * Integrates with the notification system by subscribing to notification:sent and
+ * notification:failed events on the EventBus. Each event creates a log entry in
+ * the NotificationLogRepository.
+ *
+ * Provides query methods for retrieving notification history by recipient, type,
+ * channel, status, and date range.
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { NotificationSentEvent, NotificationFailedEvent } from '../events/event-types.js';
+import type { NotificationLog, NotificationLogQuery } from '../models/notification-log.js';
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextId++).padStart(4, '0')}`;
+}
+
+/** Reset ID counter — for testing only. */
+export function resetNotificationLogIdCounter(): void {
+  nextId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(
+    private repository: NotificationLogRepository,
+    private eventBus: EventBus,
+  ) {
+    this.registerHandlers();
+  }
+
+  /**
+   * Subscribe to notification events to automatically log delivery results.
+   */
+  private registerHandlers(): void {
+    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
+      this.logNotification(event.notification, 'sent');
+    });
+
+    this.eventBus.on<NotificationFailedEvent>('notification:failed', (event) => {
+      this.logNotification(event.notification, 'failed', event.error);
+    });
+  }
+
+  /**
+   * Create a log entry for a notification delivery attempt.
+   */
+  private logNotification(
+    notification: { id: string; recipient: string; channel: NotificationLog['channel']; notificationType: NotificationLog['notificationType']; priority: NotificationLog['priority']; subject: string; metadata?: Record<string, string>; sentAt?: Date },
+    status: NotificationLog['status'],
+    error?: string,
+  ): void {
+    const logEntry: NotificationLog = {
+      id: generateLogId(),
+      notificationId: notification.id,
+      recipient: notification.recipient,
+      channel: notification.channel,
+      notificationType: notification.notificationType,
+      priority: notification.priority,
+      subject: notification.subject,
+      status,
+      error,
+      metadata: notification.metadata,
+      createdAt: new Date(),
+      deliveredAt: status === 'sent' ? (notification.sentAt ?? new Date()) : undefined,
+    };
+
+    this.repository.save(logEntry);
+    this.logger.info(`Logged notification ${notification.id} with status: ${status}`);
+  }
+
+  /**
+   * Query notification history with flexible filtering.
+   */
+  query(filter: NotificationLogQuery): NotificationLog[] {
+    return this.repository.findAll((log) => {
+      if (filter.recipient && log.recipient !== filter.recipient) return false;
+      if (filter.notificationType && log.notificationType !== filter.notificationType) return false;
+      if (filter.channel && log.channel !== filter.channel) return false;
+      if (filter.status && log.status !== filter.status) return false;
+      if (filter.startDate && log.createdAt < filter.startDate) return false;
+      if (filter.endDate && log.createdAt > filter.endDate) return false;
+      return true;
+    });
+  }
+
+  /**
+   * Get all log entries for a specific recipient.
+   */
+  getByRecipient(recipient: string): NotificationLog[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get all log entries of a specific notification type.
+   */
+  getByType(notificationType: NotificationLog['notificationType']): NotificationLog[] {
+    return this.repository.findByType(notificationType);
+  }
+
+  /**
+   * Get all log entries within a date range.
+   */
+  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
+    return this.repository.findByDateRange(startDate, endDate);
+  }
+
+  /**
+   * Get a specific log entry by ID.
+   */
+  getById(id: string): NotificationLog | undefined {
+    return this.repository.findById(id);
+  }
+
+  /**
+   * Get the total count of log entries.
+   */
+  getCount(): number {
+    return this.repository.count();
+  }
+}

