import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
import type { Notification } from '../../src/models/notification.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let eventBus: EventBus;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    eventBus = new EventBus();
    historyService = new NotificationHistoryService(repository, eventBus);
    resetNotificationLogIdCounter();
  });

  function makeNotification(overrides: Partial<Notification> = {}): Notification {
    return {
      id: 'notif-0001',
      recipient: 'alice@example.com',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed.',
      notificationType: 'order_confirmation',
      channel: 'email',
      priority: 'normal',
      status: 'sent',
      metadata: { orderId: 'order-1', userId: 'user-1' },
      createdAt: new Date('2026-01-15T10:00:00Z'),
      sentAt: new Date('2026-01-15T10:00:01Z'),
      ...overrides,
    };
  }

  describe('event-driven logging', () => {
    it('should log a sent notification from notification:sent event', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      });

      expect(historyService.getCount()).toBe(1);
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.notificationType).toBe('order_confirmation');
      expect(logs[0]?.priority).toBe('normal');
      expect(logs[0]?.subject).toBe('Order Confirmation: order-1');
      expect(logs[0]?.deliveredAt).toBeDefined();
    });

    it('should log a failed notification from notification:failed event', async () => {
      await eventBus.emit({
        type: 'notification:failed',
        notification: makeNotification({ status: 'failed' }),
        error: 'SMTP connection refused',
        timestamp: new Date(),
      });

      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.error).toBe('SMTP connection refused');
      expect(logs[0]?.deliveredAt).toBeUndefined();
    });

    it('should generate sequential log IDs', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0001' }),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }),
        timestamp: new Date(),
      });

      const log1 = historyService.getById('nlog-0001');
      const log2 = historyService.getById('nlog-0002');
      expect(log1).toBeDefined();
      expect(log2).toBeDefined();
      expect(log1?.notificationId).toBe('notif-0001');
      expect(log2?.notificationId).toBe('notif-0002');
    });

    it('should preserve metadata from notification', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ metadata: { orderId: 'order-42', userId: 'user-7' } }),
        timestamp: new Date(),
      });

      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs[0]?.metadata).toEqual({ orderId: 'order-42', userId: 'user-7' });
    });
  });

  describe('query by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ recipient: 'alice@example.com' }),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }),
        timestamp: new Date(),
      });

      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('bob@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('charlie@example.com')).toHaveLength(0);
    });
  });

  describe('query by type', () => {
    it('should return logs for a specific notification type', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ notificationType: 'order_confirmation' }),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002', notificationType: 'order_status_update' }),
        timestamp: new Date(),
      });

      expect(historyService.getByType('order_confirmation')).toHaveLength(1);
      expect(historyService.getByType('order_status_update')).toHaveLength(1);
      expect(historyService.getByType('welcome')).toHaveLength(0);
    });
  });

  describe('query by date range', () => {
    it('should return logs within the specified date range', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      });

      // The log's createdAt is set to "now" in the service, so use a wide range
      const start = new Date(Date.now() - 60000);
      const end = new Date(Date.now() + 60000);

      expect(historyService.getByDateRange(start, end)).toHaveLength(1);
    });

    it('should exclude logs outside the date range', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      });

      const futureStart = new Date('2099-01-01T00:00:00Z');
      const futureEnd = new Date('2099-12-31T23:59:59Z');

      expect(historyService.getByDateRange(futureStart, futureEnd)).toHaveLength(0);
    });
  });

  describe('flexible query', () => {
    beforeEach(async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          notificationType: 'order_confirmation',
          channel: 'email',
        }),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:failed',
        notification: makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          notificationType: 'order_status_update',
          channel: 'webhook',
          status: 'failed',
        }),
        error: 'Timeout',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({
          id: 'notif-0003',
          recipient: 'alice@example.com',
          notificationType: 'welcome',
          channel: 'email',
        }),
        timestamp: new Date(),
      });
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
    });

    it('should filter by notification type', () => {
      const results = historyService.query({ notificationType: 'order_confirmation' });
      expect(results).toHaveLength(1);
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        notificationType: 'welcome',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationType).toBe('welcome');
    });

    it('should return all logs with empty filter', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });

    it('should filter by date range', () => {
      const start = new Date(Date.now() - 60000);
      const end = new Date(Date.now() + 60000);
      const results = historyService.query({ startDate: start, endDate: end });
      expect(results).toHaveLength(3);
    });
  });

  describe('integration with NotificationService', () => {
    let notificationService: NotificationService;

    beforeEach(() => {
      notificationService = new NotificationService(eventBus);
      resetNotificationIdCounter();

      // Register a mock adapter that succeeds
      notificationService.registerAdapter({
        channel: 'email',
        async send() {
          return { success: true, channel: 'email' };
        },
      });
    });

    it('should log notifications dispatched through NotificationService', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Allow adapter promise to resolve and notification:sent event to fire
      await new Promise((resolve) => setTimeout(resolve, 0));

      expect(historyService.getCount()).toBe(1);
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationType).toBe('order_confirmation');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.channel).toBe('email');
    });

    it('should log failed notifications from adapter errors', async () => {
      // Replace adapter with one that fails
      notificationService.registerAdapter({
        channel: 'email',
        async send() {
          return { success: false, channel: 'email', error: 'Delivery failed' };
        },
      });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);
      await new Promise((resolve) => setTimeout(resolve, 0));

      expect(historyService.getCount()).toBe(1);
      const logs = historyService.query({ status: 'failed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.error).toBe('Delivery failed');
    });

    it('should log failed notifications from adapter exceptions', async () => {
      notificationService.registerAdapter({
        channel: 'email',
        async send() {
          throw new Error('Connection timeout');
        },
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      await new Promise((resolve) => setTimeout(resolve, 0));

      const logs = historyService.query({ status: 'failed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.error).toBe('Connection timeout');
    });
  });

  describe('getById', () => {
    it('should return a log entry by ID', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      });

      const log = historyService.getById('nlog-0001');
      expect(log).toBeDefined();
      expect(log?.id).toBe('nlog-0001');
    });

    it('should return undefined for non-existent ID', () => {
      expect(historyService.getById('nlog-9999')).toBeUndefined();
    });
  });

  describe('getCount', () => {
    it('should return 0 when no logs exist', () => {
      expect(historyService.getCount()).toBe(0);
    });

    it('should return correct count after logging', async () => {
      await eventBus.emit({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0001' }),
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'notification:failed',
        notification: makeNotification({ id: 'notif-0002' }),
        error: 'Error',
        timestamp: new Date(),
      });

      expect(historyService.getCount()).toBe(2);
    });
  });
});
